var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"한 해의 끝을 장식하는 성스러운 밤.","JPN":"一年の終わりを飾る聖なる夜。","ENG":"The holy night comes at the end of every year.","TWN":"點綴一年之末的神聖之夜。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"이 밤에는 누구나 따뜻한 모닥불의 온기 속에서 일 년간의 즐거운 추억들을 떠올리곤 하지.","JPN":"この夜は誰もが暖かな暖炉を囲い、一年間の楽しい思い出を語り合う。","ENG":"During this night, people all over the hearth gather, sharing memories of the good moments from the year.","TWN":"在這個夜晚，每個人都會在溫暖的篝火前，回想過去一年中快樂的回憶。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만...... 세상 모든 일이 그렇듯이 예외는 있는 법이라네.","JPN":"しかし……例外が存在するのも世の常。","ENG":"But... just like everything else in the world, there's an exception.","TWN":"但是……總會有那麼一兩個意外，世事便是如此。"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"예를 들어...... 해마다 어떤 산장에 나타난다고 알려진 <color=#ffd34c>성야의 살인마</color>처럼.","JPN":"例えば……毎年ある山荘に現れると言われている<color=#ffd34c>聖夜の殺人鬼</color>のように。","ENG":"The <color=#ffd34c>Killer of the Holy Night</color>, for example, is believed to appear at a certain mountain cabin every year.","TWN":"比如就像……某個山莊每年都會出現的<color=#ffd34c>耶誕的嫌疑犯</color>。"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......꿀꺽.","JPN":"……(ごくり)","ENG":"*Gulp*","TWN":"……咕嚕。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOOSHIYOON_XMAS_NULL_NULL","text":{"KOREA":"산장이라...... 그게 설마 이 산장은 아니겠죠?","JPN":"山荘ですか……まさかこの山荘のことではありませんよね？","ENG":"A mountain cabin... It can't be this one, can it?","TWN":"山莊……不會就是這個山莊吧？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_XMAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"왜 아니겠나?","JPN":"そのまさかだが？","ENG":"Why not?","TWN":"懷疑嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이 산장이 성야의 살인마가 출몰한다는 바로 그 공포의 산장일세.","JPN":"ここが聖夜の殺人鬼が現れるという、その恐怖の山荘だ。","ENG":"As a matter of fact, it is the very cabin rumored to be haunted by the Killer of the Holy Night.","TWN":"這個山莊就是耶誕的嫌疑犯出沒的那個可怕的山莊。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"하, 하지만 여기 있는 사람들은 모두 한가락 하는 카운터들이잖아?","JPN":"で、でもここにいるのはみんな、腕の立つカウンターたちでしょ？","ENG":"B-but everyone here is a Counter worth their salt.","TWN":"可、可是聚在這裡的人，不都是有能力的制裁者嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"살인마 따위가 덤벼들어 봤자 3초 컷이지.","JPN":"殺人鬼なんかがやって来たところで、3秒で終わりよ。","ENG":"Even the Killer wouldn't last three seconds against us.","TWN":"即使有殺人魔，估計三秒內就會被幹掉吧。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"안 그래, 버터맨?","JPN":"バターマンもそう思うでしょ？","ENG":"Don't you agree, Sleazeball?","TWN":"你說呢，油膩男？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"걱정 말라고, 실비아.","JPN":"心配するな、シルビア。","ENG":"Don't worry, Sylvia.","TWN":"不用擔心，希爾維亞。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"무슨 유령 같은 게 아닌 이상, 이 비공인 탑 카운터 님이 한 방에 쓰러트려 줄 테니까.","JPN":"幽霊みたいなものでなければ、この非公認トップカウンター様が一発で仕留めてやるさ。","ENG":"Unless this Killer is some sort of ghost, I, the unofficial top Counter, could get rid of him with a single blow.","TWN":"只要不是鬼，我這個非公認制裁者就能一拳把他打趴下。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"후후. 그런 단순한 범죄자라면 <color=#ffd34c>성야의 살인마</color>라는 이명이 붙지도 않았겠지.","JPN":"そんな単純な犯罪者なら<color=#ffd34c>聖夜の殺人鬼</color>という異名がつくこともなかっただろう。","ENG":"Hah hah. If he was so easy to get rid of, he wouldn't have been called the <color=#ffd34c>Killer of the Holy Night</color>, now would he?","TWN":"哼，如果這麼容易就能打敗，就不會有<color=#ffd34c>耶誕的嫌疑犯</color>這個綽號了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"살을 에는 북풍의 눈보라가 몰아치는 어두운 밤,","JPN":"肌を切るような北風の吹雪が吹き荒れる暗い夜。","ENG":"Legend says, during the dark, stormy winter night,","TWN":"在刺骨的暴風雪肆虐的黑夜，"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"살인마는 산장의 그림자 속에서 소리 없이 나타난다네.","JPN":"殺人鬼は山荘の影の中から音もなく現れるそうだ。","ENG":"the Killer would silently emerge out of the shadow of the cabin,","TWN":"殺人魔會悄無聲息地來到山莊。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그리고는 불운한 희생양의 이마에 사냥감의 낙인을 찍지.","JPN":"そして、不運な犠牲者の額に獲物の烙印を押すんだ。","ENG":"and brand an unfortunate scapegoat with the mark of prey on his forehead.","TWN":"然後在不幸的代罪羔羊額頭上留下代表獵物的印記。"},"stage":{"bg":"X_MAS_HOUSE","bgm":"THEMA_ESPR","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"낙인이 찍힌 희생양은 이성을 잃은 채 날뛰다가 흔적도 없이 사라져 버린다고 하네.","JPN":"その烙印を押された犠牲者は理性を失い暴れた後、跡形もなく消え去ってしまうそうだ。","ENG":"This branded scapegoat then would lose his mind and run amok until he disappears without a trace,","TWN":"而被印上獵物印記的人會變得喪心病狂，之後便消失地無影無蹤。"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"마치......","JPN":"まるで……","ENG":"as if...","TWN":"就像……"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"유령에게 홀린 것처럼 말이야.","JPN":"幽霊に憑りつかれたかのように。","ENG":"he's possessed by a ghost.","TWN":"被鬼勾了魂一樣。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"유, 유령......? 농담이지?","JPN":"ゆ、幽霊……？　冗談でしょ？","ENG":"A-a-a ghost? You're kidding, right?","TWN":"鬼、鬼……？開玩笑吧？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"곤란하군. 아무리 나라고 해도 심령 현상을 상대로 싸우기는 좀......","JPN":"困ったな。いくら俺でも心霊現象を相手に戦うのは……","ENG":"That's not good. Even I can't fight a ghost.","TWN":"這就有點麻煩了，即使是我，也無法和靈異的東西打一架……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"괘...... 괜찮아! 심령 버라이어티에서 유령은 전자기파에 약하다고 했으니까!","JPN":"だ……大丈夫よ！　心霊バラエティーとかで幽霊は電磁波に弱いって言ってたし！","ENG":"W-we'll be fine! According to this supernatural show I watched, ghosts are vulnerable to electromagnetic waves.","TWN":"沒……沒關係！幽靈探險節目上說過，鬼面對電磁波是非常弱的！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"두 분 다 한심하군요. 세상에 유령이 어디 있다고 그렇게 벌벌 떠시는 겁니까?","JPN":"二人とも情けないですね。この世に幽霊などいるわけないのに、何を怯えているのですか？","ENG":"Both of you are pathetic, trembling like that. There's no such thing as ghosts.","TWN":"你們倆真是夠了，這世上哪來的鬼，用得著那麼瑟瑟發抖嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"시끄러! 누구더러 벌벌 떤다는 거야?!","JPN":"うるさい！　誰が怯えてるって！？","ENG":"Shut up! No one's trembling!","TWN":"閉嘴！誰瑟瑟發抖了？！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"그냥 옷이 얇아서 추위 좀 타는 거 가지고!","JPN":"これはその……ただ薄着で寒かっただけよ！","ENG":"I just feel a little bit cold because my clothes are not thick enough!","TWN":"我只是穿的薄了些，有點冷而已！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふぅ……","ENG":"*Sigh...*","TWN":"呼……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"심령 현상은 이미 침식파가 일으키는 여러 이변 중 하나로 밝혀진 바 있습니다.","JPN":"心霊現象はすでに侵食波が起こす、いくつかの異変の一つだと明らかにされています。","ENG":"It has already been proven that such psychic phenomena are one of the disturbances caused by Corruption rays.","TWN":"靈異現象已經被證實是侵蝕波引起的諸多異變之一。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그런데 실비아 씨도 모자라서 대령님까지 저런 황당한 이야기를 믿으실 줄은 몰랐군요.","JPN":"しかし、シルビアさんだけでなく大佐まであのようなバカげた話を信じるとは思いもしませんでした。","ENG":"It's totally incredible that you believe such a ridiculous story. Not only Sylvia, but also you, Colonel.","TWN":"希爾維亞就算了，上校大人怎麼會聽信那種荒唐的故事呢。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"아무래도 내년부터는 정규 훈련 코스에 담력시험도 편성해야겠습니다.","JPN":"やはり、来年からは正規訓練コースに胆力テストも編成した方が良さそうですね。","ENG":"You're making me seriously consider including a bravery test in our regular training course next year.","TWN":"看來明年的正規訓練裡有必要加一條膽量考驗了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"큭...... 쓸데없이 깐깐하긴......","JPN":"くっ……無駄に几帳面なんだから。","ENG":"Aww... Stop being so fastidious.","TWN":"咳……幹嘛這麼苛刻……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"애초에 왜 이런 기분 나쁜 산장에서 연말 파티를 하는 거야?","JPN":"そもそも、どうしてこんな薄気味悪い山荘で忘年会なんかするわけ？","ENG":"Why do we have to celebrate the end of the year in such a creepy place, anyway?","TWN":"為什麼非得在這種不吉利的山莊辦年終晚會？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"산속 깊숙이 박혀서 지도에도 안 나오는 곳이잖아.","JPN":"山奥過ぎて地図にも載ってなかったわよ？","ENG":"It's so remote that it doesn't even show on the map.","TWN":"而且，這地方偏僻的連在地圖上都找不到。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"여기까지 오느라 얼마나 고생했는지 알아?","JPN":"ここまで来るのに苦労したんだからね！","ENG":"Do you know how hard it was for us to get here?","TWN":"你知道我是怎麼辛辛苦苦地來到這裡的嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그건 쓸데없이 불편한 옷을 차려 입고 온 실비아 양의 책임도 있는 것 같습니다만.","JPN":"それは無駄に不便な服装で来たシルビアさんにも責任があるのでは？","ENG":"I believe that's partly attributed to your inappropriately uncomfortable attire, Sylvia.","TWN":"我覺得，希爾維亞妳穿著那麼不方便的衣服，難免來的路上會有點辛苦。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"연말 파티라길래 호텔 연회장이라도 빌린 줄 알았지!","JPN":"忘年会って言うから、ホテルの宴会場でも借りてくれたんだと思ったの！","ENG":"This was supposed to be a year-end party! I thought I was going to a hotel banquet hall!","TWN":"我以為是在什麼酒店的宴會廳辦年終晚會呢！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이런 깡촌 중에 깡촌이란 소린 한마디도 못 들었다고!","JPN":"こんなド田舎の中でも超ド田舎でやるなんて聞いてないわ！","ENG":"Not a backwater hut like this!","TWN":"沒有人告訴我是在這種鄉下地方呀！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"뭐, 이런 데서 여는 이유가 따로 있겠나.","JPN":"まあ、こんなところで開いた理由は決まっている。","ENG":"Well, we chose this place for a simple reason.","TWN":"在這裡辦晚會，還能有什麼理由。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그런 흉흉한 소문이 있는 만큼 대여료가 가장 싸기 때문이지.","JPN":"そのような怖い噂がある所ほど、レンタル料が安いのだ。","ENG":"It was the cheapest place to rent, being so infamous.","TWN":"因為是凶宅，所以租金比較便宜啊。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......아, 그러셔?","JPN":"……あぁ、そうですか？","ENG":"Oh, yeah?","TWN":"……啊，是嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이제 됐어. 난 돌아갈래.","JPN":"もういい、アタシは帰る。","ENG":"That's it. I'm leaving.","TWN":"算了，我要回去了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"실비아 씨, 여기까지 와서 갑자기 무슨 변덕입니까?","JPN":"シルビアさん、わざわざここまで来たのに帰るのですか？","ENG":"Sylvia, if you were going to leave so soon, why did you even come?","TWN":"希爾維亞，妳來都來了，怎麼說走就走呢？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"파티 한대서 왔지 공포 체험 하러 온 줄 알아?","JPN":"パーティーだって言うから来たのに、肝試しなんかごめんよ。","ENG":"I came for a party, not for a horror experience.","TWN":"我是來參加派對的，不是來體驗凶宅的好嗎？"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"이런 기분 나쁜 곳엔 단 1초도 더 있기 싫거든?","JPN":"こんな薄気味悪い場所に、これ以上いたくないわ！","ENG":"I don't want to be in this creepy place any longer!","TWN":"我連一秒都不想待在這種不吉利的地方。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"차라리 다─크세븐 멍청이들이랑 스페이스 인베이더나 하는 게 훨씬 생산적이겠다.","JPN":"いっそ、ダークセブンのおバカさんたちとスペースインベーダーでもしてた方がずっと生産的ね。","ENG":"I'd rather play Space Invader with those Daark Seven idiots.","TWN":"還不如和黑暗七號的傻瓜們玩太空侵略者呢。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"진정하시죠, 실비아 씨.","JPN":"落ち着いてください、シルビアさん。","ENG":"Please calm down, Sylvia.","TWN":"冷靜點，希爾維亞。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"우리가 여기 온 건 단순히 친목 파티에 참석하기 위해서가 아닙니다.","JPN":"私たちがここに来たのは、ただの親睦会に参加するためではありません。","ENG":"We didn't just come here to party.","TWN":"我們來這裡並不是只為了參加聯誼晚會。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"리플레이서 사태 때 드러났던 코핀 컴퍼니의 수상함을 벌써 잊으셨습니까?","JPN":"リプレイサー事件で露わになったコフィンカンパニーの奇妙な動きを忘れたのですか？","ENG":"Did you already forget how suspicious the Coffin Company was during the Replacer incident?","TWN":"難道妳已經忘了克隆集團事件時科芬公司的可疑之處嗎？"},"stage":{"bg":"MAINSTREAM_5506012","bgm":"THEMA_XMAS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"우린 그 비밀을 파헤치라는 중장님의 지시로 파티에 참가한 겁니다.","JPN":"私たちはその秘密を暴けという中将の命令でパーティーに参加しているのです。","ENG":"We came here to uncover its secrets as it was the Lieutenant General's order.","TWN":"中將讓我們參加派對，就是想要我們揭開他們的秘密。"},"stage":{"bg":"MAINSTREAM_5506012","bgm":"THEMA_XMAS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"끄응......","JPN":"ううっ……","ENG":"*Groan*","TWN":"呃……"},"stage":{"bg":"MAINSTREAM_5506012","bgm":"THEMA_XMAS","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"중장님 지시와는 별개로 지금 산을 내려가는 건 나도 반대야.","JPN":"中将の命令をさておいても、今から山を下るのは俺も反対だ。","ENG":"Aside from it being the Lieutenant General's order, I don't think it's safe to go down the mountain right now.","TWN":"而且就算沒有中將的命令，我也反對妳現在下山。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"눈보라가 너무 심해. 지금쯤이면 아마 길이 전부 눈 속에 파묻혔을 거다.","JPN":"この吹雪だぞ。山道も雪で埋まってしまっている。","ENG":"It's way too stormy outside. The road must be buried under snow by now.","TWN":"暴風雪太大，估計下山的路都被雪堵住了。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"수송선이라도 부르지 않는 한 내일 아침까지 산장을 벗어나긴 힘들 것 같군.","JPN":"輸送船でも呼ばない以上、明朝まで山荘を出るのは難しいだろう。","ENG":"Unless we call for a transport ship, we can't leave the cabin until tomorrow morning.","TWN":"除非我們叫個車，否則一直到明天早上估計都很難離開山莊。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"그러니 무의미한 불평은 그만두고 임무에 집중하시길 바랍니다.","JPN":"だから無意味な不平不満はやめて、任務に集中してください。","ENG":"So please stop complaining and focus on the mission.","TWN":"所以就不要做無意義的抱怨了，還是專心做事吧。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저도 지금부터 파티 관계자들에 대한 탐문을 시작할 테니까요.","JPN":"私も今からパーティー関係者に聞き取りを始めます。","ENG":"I myself will start interviewing the party staff from now on.","TWN":"我現在就要去打聽關於派對負責人的事。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"하아......","JPN":"はぁ……","ENG":"*Sigh...*","TWN":"哈啊……"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SYLVIA_XMAS_NULL_NULL","text":{"KOREA":"네, 네. 아주 자알~ 알겠습니다~","JPN":"はいはい。よ～くわかりました。","ENG":"Yeah, yeah. Whatever you say.","TWN":"好，好，我知~道了~"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_XMAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그럼 손님들도 모두 모인 것 같으니, 정식으로 코핀 컴퍼니 송년 파티를 시작하겠네!","JPN":"では全員集まったようだから、正式にコフィンカンパニー忘年会を始めよう！","ENG":"Now that everyone's here, let's begin the Coffin Company's year-end party!","TWN":"看來人已經來的差不多了，科芬公司的年終晚會正式開始！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"돌이켜 보면 올 한 해 동안 참으로 많은 일들이 있었지.","JPN":"思い返せば、今年も多事多端な一年だったな。","ENG":"Looking back, I realized a lot of things happened this year.","TWN":"回顧過去一年，今年真的發生了很多事情。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"하지만 여기 모인 사람들의 헌신 덕분에 우리 회사는 위기를 극복하고 더 좋은 성과를 낼 수 있었다네.","JPN":"しかし、ここに集まった人々のおかげで、我が社は危機を乗り越えて良い結果を出すことができたのだ。","ENG":"But thanks to everyone, the company overcame difficulties and actually has done better than ever.","TWN":"但多虧了在座的各位無私奉獻，我們公司克服了危機，並取得了更好的成果。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그간 회사에 도움을 준 외부 인사들도 초대했으니, 이 기회에 서로 친목을 다지면 좋겠군.","JPN":"今まで我が社に力を貸してくれた外部の方々にも来てもらったんだ、この機会に親睦を深めてくれ。","ENG":"Our affiliates have been invited to this party as well. I hope all of you will enjoy this party and each other's company.","TWN":"我們還邀請了對公司提供幫助的外部人士，希望大家能趁這個機會互相認識一下。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아, 혹시 파티 중에 필요한 것이 있으면 여기 베로니카 양에게 부탁하면 된다네.","JPN":"あ、もし何か必要なものがあれば、ここにいるベロニカに頼みなさい。","ENG":"Ah, and if you need anything during the party, please ask Veronica here.","TWN":"對了，如果有什麼需要，可以隨時找貝洛妮卡小姐。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"송년 파티 진행을 맡은<color=#ffd34c> 플로라 메이드 서비스</color>의 메이드장, 베로니카라고 합니다.","JPN":"忘年会の進行を任された<color=#ffd34c>フローラメイドサービス</color>のメイド長、ベロニカと申します。","ENG":"I'm Veronica, the Chief Maid of the <color=#ffd34c>Flora Maid Service</color> in charge of this year-end party.","TWN":"我是這次年終晚會的主持人，<color=#ffd34c>芙蘿拉女僕服務公司</color>的女僕長，貝洛妮卡。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"LEADER_XMAS_NULL_NULL","text":{"KOREA":"오늘 하루, 귀빈 여러분의 즐거움을 위해 혼신을 다하겠습니다.","JPN":"今日一日、皆様に楽しくお過ごしいただけるよう努めさせていただきます。","ENG":"I'll do my best to serve you, my valued guests, for the rest of the day.","TWN":"今天，我將竭盡全力為大家服務，希望各位貴賓能盡情享受。"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_XMAS_NULL_NULL","text":{"KOREA":"견습 메이드 모네임다! 뭐든 맡겨만 주시지 말임다!","JPN":"見習いメイドのモネ！　何でもお任せくださいっす！","ENG":"I'm Mone, a maid-in-training, sirs! Count on me for anything!","TWN":"我是見習女僕莫妮！什麼事都可以交給我！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEADER_XMAS_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"TONFA_XMAS_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_WIND2"},{"id":"L5_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"자! 차린 건 없지만 마음껏 즐겨주게나!","JPN":"じゃあ、心置きなく楽しんでくれ！","ENG":"Now, enjoy this feast!","TWN":"來！我們為大家準備了吃的，希望大家能盡情享受！"},"stage":{"bg":"X_MAS_ROOM","bgm":"THEMA_XMAS","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};